import React, { useEffect, useRef } from 'react';
import styled from 'styled-components';
import { srConfig } from '@config';
import sr from '@utils/sr';
import { usePrefersReducedMotion } from '@hooks';

const StyledAboutSection = styled.section`
  max-width: 100%;

  .inner {
    display: grid;
    grid-template-columns: minmax(0, 1fr);
    gap: 34px;
  }
`;

const StyledText = styled.div`
  p {
    font-size: var(--fz-md);
    line-height: 1.8;
    max-width: 72ch;
  }

  ul.skills-list {
    display: grid;
    grid-template-columns: repeat(2, minmax(240px, 1fr));
    grid-gap: 10px 24px;
    max-width: 620px;
    padding: 0;
    margin: 20px 0 0 0;
    overflow: hidden;
    list-style: none;

    li {
      position: relative;
      padding-left: 20px;
      font-family: var(--font-mono);
      font-size: var(--fz-xs);
      line-height: 1.55;
      white-space: nowrap;

      &:before {
        content: '▹';
        position: absolute;
        left: 0;
        color: var(--green);
        font-size: var(--fz-sm);
        line-height: 12px;
      }
    }

    @media (max-width: 640px) {
      grid-template-columns: 1fr;

      li {
        white-space: normal;
      }
    }
  }

  .about-callout {
    margin-top: 16px;
    max-width: 72ch;
    color: var(--dark-slate);
  }
`;

const About = () => {
  const revealContainer = useRef(null);
  const prefersReducedMotion = usePrefersReducedMotion();

  useEffect(() => {
    if (prefersReducedMotion) {
      return;
    }

    sr.reveal(revealContainer.current, srConfig());
  }, []);

  const skills = [
    'Collaborative mindset',
    'Low-ego communication',
    'Self-starter execution',
    'Strategic thinking',
    'User-first decision making',
    'Cross-functional leadership',
  ];

  return (
    <StyledAboutSection id="about" ref={revealContainer}>
      <h2 className="numbered-heading">About Me</h2>

      <div className="inner">
        <StyledText>
          <p>
            Hello, I’m Robin. I’m a software engineer with 6+ years of experience designing scalable backend
            systems, distributed event-driven architectures, and cloud-native applications.
          </p>

          <p>
            I’ve had the privilege of contributing to teams at{' '}
            <a href="https://basis.com/">Basis Technologies</a>, LightBox, and DaveSimmons.io.
          </p>

          <p>A few strengths I bring to product teams:</p>

          <p>
            I’m at my best when a system needs to become faster, more observable, and easier to operate. I like
            turning complex workflows into clear services, dependable APIs, and deployment paths that teams can
            trust.
          </p>

          <p className="about-callout">
            My recent work spans Python services, Kafka and RabbitMQ pipelines, PostgreSQL optimization, Redis
            caching, AWS infrastructure, Kubernetes deployments, Terraform automation, and CI/CD systems that
            reduce release friction.
          </p>

          <ul className="skills-list">
            {skills && skills.map((skill, i) => <li key={i}>{skill}</li>)}
          </ul>
        </StyledText>
      </div>
    </StyledAboutSection>
  );
};

export default About;
