const Layout = ({ children, location }) => {
  const isHome = location.pathname === '/';
  const isDarkEditorial =
    isHome ||
    location.pathname.startsWith('/blog') ||
    location.pathname.startsWith('/work') ||
    location.pathname.startsWith('/archive');
  const contentRef = useRef(null);

  const handleExternalLinks = () => {
    const allLinks = Array.from(document.querySelectorAll('a'));
    if (allLinks.length > 0) {
      allLinks.forEach(link => {
        if (link.host !== window.location.host) {
          link.setAttribute('rel', 'noopener noreferrer');
          link.setAttribute('target', '_blank');
        }
      });
    }
  };

  useEffect(() => {
    if (location.hash) {
      const id = location.hash.substring(1);
      setTimeout(() => {
        const el = document.getElementById(id);
        if (el) {
          el.scrollIntoView();
          el.focus();
        }
      }, 0);
    }

    handleExternalLinks();
  }, [location.hash]);

  useEffect(() => {
    if (typeof window === 'undefined') {
      return undefined;
    }

    const syncTimeTheme = () => {
      const themeName = getTimeTheme(new Date());
      document.documentElement.setAttribute('data-time-theme', themeName);
      document.body.setAttribute('data-time-theme', themeName);
    };

    syncTimeTheme();

    const interval = window.setInterval(syncTimeTheme, 60 * 1000);

    return () => {
      window.clearInterval(interval);
    };
  }, []);

  useEffect(() => {
    if (typeof window === 'undefined' || !contentRef.current) {
      return undefined;
    }

    const content = contentRef.current;
    const prefersReducedMotion = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
    const prefersFinePointer = window.matchMedia('(pointer: fine)').matches;

    if (prefersReducedMotion || !prefersFinePointer) {
      content.style.setProperty('--spotlight-x', '50vw');
      content.style.setProperty('--spotlight-y', '24vh');
      return undefined;
    }

    let animationFrame = null;

    const moveSpotlight = event => {
      if (animationFrame) {
        window.cancelAnimationFrame(animationFrame);
      }

      animationFrame = window.requestAnimationFrame(() => {
        content.style.setProperty('--spotlight-x', `${event.clientX}px`);
        content.style.setProperty('--spotlight-y', `${event.clientY}px`);
      });
    };

    window.addEventListener('pointermove', moveSpotlight, { passive: true });

    return () => {
      window.removeEventListener('pointermove', moveSpotlight);
      if (animationFrame) {
        window.cancelAnimationFrame(animationFrame);
      }
    };
  }, [isDarkEditorial]);

  return (
    <>
      <Head />

      <div id="root">
        <ThemeProvider theme={theme}>
          <GlobalStyle />

          <a className="skip-to-content" href="#content">
            Skip to Content
          </a>

          <StyledContent ref={contentRef} $darkEditorial={isDarkEditorial}>
            <StyledSpotlight aria-hidden="true" />
            <BoundaryMicroGeometry />

            <Nav isHome={isHome} location={location} isDarkEditorial={isDarkEditorial} />
            {!isHome && !isDarkEditorial && <Social isHome={isHome} />}
            {!isHome && !isDarkEditorial && <Email isHome={isHome} />}

            <StyledPageContent id="content" tabIndex="-1">
              {children}
              {!isHome && !isDarkEditorial && <Footer />}
            </StyledPageContent>

            {!isHome && !isDarkEditorial && <BackToTop />}
          </StyledContent>
        </ThemeProvider>
      </div>
    </>
  );
};

Layout.propTypes = {
  children: PropTypes.node.isRequired,
  location: PropTypes.object.isRequired,
};

export default Layout;
