import React, { useEffect, useRef } from 'react';
import { graphql, Link, useStaticQuery } from 'gatsby';
import styled from 'styled-components';
import { srConfig } from '@config';
import sr from '@utils/sr';
import { usePrefersReducedMotion } from '@hooks';

const StyledBlogPreviewSection = styled.section`
  display: flex;
  flex-direction: column;
  align-items: stretch;

  .header-row {
    ${({ theme }) => theme.mixins.flexBetween};
    width: 100%;
    align-items: flex-end;
    gap: 14px;
  }

  .all-posts-link {
    font-size: var(--fz-sm);
    font-weight: 600;
    font-family: var(--font-ui);
    white-space: nowrap;
    flex-shrink: 0;

    &:after {
      bottom: 0.1em;
    }
  }

  .posts-grid {
    ${({ theme }) => theme.mixins.resetList};
    width: 100%;
    display: grid;
    gap: 0;
    margin-top: 34px;
  }
`;

const StyledPost = styled.li`
  margin: 0 -18px;
  padding: 0 18px;
  border: 1px solid transparent;
  border-top: 1px solid var(--lightest-navy);
  border-radius: 14px;
  transition: background-color 180ms ease, border-color 180ms ease, box-shadow 180ms ease, transform 180ms ease;

  &:first-of-type {
    border-top-color: transparent;
  }

  @media (prefers-reduced-motion: no-preference) {
    &:hover,
    &:focus-within {
      transform: translateY(-2px);
    }
  }

  &:hover,
  &:focus-within {
    background-color: rgba(255, 255, 255, 0.64);
    border-color: rgba(82, 106, 120, 0.18);
    box-shadow: 0 16px 36px -30px var(--navy-shadow);
  }

  .post-card {
    display: grid;
    grid-template-columns: 110px minmax(0, 1fr);
    gap: 18px;
    align-items: start;
    padding: 18px 0;

    @media (max-width: 768px) {
      grid-template-columns: 1fr;
      gap: 8px;
      padding: 16px 0;
    }
  }

  .post-meta {
    color: var(--light-slate);
    font-family: var(--font-ui);
    font-size: var(--fz-sm);
    font-weight: 500;
    letter-spacing: 0.03em;
    white-space: nowrap;
    text-transform: uppercase;
  }

  .post-link {
    display: inline-flex;
    align-items: baseline;
    gap: 10px;
    color: var(--lightest-slate);
    font-size: clamp(20px, 2.3vw, 24px);
    line-height: 1.25;
    transition: var(--transition);

    &:after {
      content: '↗';
      color: var(--green);
      font-size: var(--fz-sm);
    }
  }

  .post-title {
    margin: 0;
  }

  .post-desc {
    margin: 8px 0 0;
    color: var(--slate);
    font-size: var(--fz-sm);
    line-height: 1.65;
    max-width: 58ch;
  }

  .post-tags {
    ${({ theme }) => theme.mixins.resetList};
    display: flex;
    flex-wrap: wrap;
    gap: 8px;
    margin-top: 10px;
  }

  .post-tag {
    color: var(--green);
    font-family: var(--font-mono);
    font-size: var(--fz-xxs);
    line-height: 1.4;
  }
`;

const HomeBlogPreview = () => {
  const data = useStaticQuery(graphql`
    query {
      posts: allMarkdownRemark(
        filter: {
          fileAbsolutePath: {
            regex: "/content/posts/(?!saas-is-not-dead|hiring-is-human|into-their-world|thomas-and-therify|thomas-and-startup-culture)/"
          }
          frontmatter: { draft: { ne: true } }
        }
        sort: { fields: [frontmatter___date], order: DESC }
        limit: 3
      ) {
        edges {
          node {
            frontmatter {
              title
              description
              slug
              date
              tags
            }
          }
        }
      }
    }
  `);

  const revealTitle = useRef(null);
  const revealLink = useRef(null);
  const revealPosts = useRef([]);
  const prefersReducedMotion = usePrefersReducedMotion();

  useEffect(() => {
    if (prefersReducedMotion) {
      return;
    }

    sr.reveal(revealTitle.current, srConfig());
    sr.reveal(revealLink.current, srConfig());
    revealPosts.current.forEach((ref, i) => sr.reveal(ref, srConfig(i * 100)));
  }, []);

  const posts = data.posts.edges.filter(({ node }) => node);

  return (
    <StyledBlogPreviewSection>
      <div className="header-row">
        <h2 className="numbered-heading" ref={revealTitle}>
          Latest Insights
        </h2>
        <Link to="/blog" className="inline-link all-posts-link" ref={revealLink}>
          Read All Posts
        </Link>
      </div>

      <ul className="posts-grid">
        {posts.map(({ node }, i) => {
          const { title, description, slug, date, tags } = node.frontmatter;

          return (
            <StyledPost key={slug} ref={el => (revealPosts.current[i] = el)}>
              <article className="post-card">
                <div className="post-meta">{new Date(date).toLocaleDateString()}</div>

                <div>
                  <h3 className="post-title">
                    <Link to={slug} className="post-link">
                      {title}
                    </Link>
                  </h3>
                  <p className="post-desc">{description}</p>

                  <ul className="post-tags">
                    {(tags || []).slice(0, 3).map(tag => (
                      <li className="post-tag" key={`${slug}-${tag}`}>
                        #{tag}
                      </li>
                    ))}
                  </ul>
                </div>
              </article>
            </StyledPost>
          );
        })}
      </ul>
    </StyledBlogPreviewSection>
  );
};

export default HomeBlogPreview;
