import React, { useState, useEffect, useMemo } from 'react';
import { Link } from 'gatsby';
import PropTypes from 'prop-types';
import { CSSTransition, TransitionGroup } from 'react-transition-group';
import styled, { css } from 'styled-components';
import { navLinks } from '@config';
import { loaderDelay } from '@utils';
import { useScrollDirection, usePrefersReducedMotion } from '@hooks';
import { Menu } from '@components';
import { IconLogo, IconHex } from '@components/icons';

const StyledHeader = styled.header`
  ${({ theme }) => theme.mixins.flexBetween};
  position: fixed;
  top: 0;
  z-index: 11;
  padding: 0px 42px;
  width: 100%;
  height: 94px;
  background-color: rgba(255, 255, 255, 0.82);
  border-bottom: 1px solid rgba(31, 41, 55, 0.08);
  box-shadow: 0 10px 30px -24px rgba(31, 41, 55, 0.18);
  filter: none !important;
  pointer-events: auto !important;
  user-select: auto !important;
  backdrop-filter: blur(12px);
  transition: var(--transition);

  @media (max-width: 1080px) {
    padding: 0 40px;
  }
  @media (max-width: 768px) {
    padding: 0 25px;
  }

  @media (prefers-reduced-motion: no-preference) {
    ${props =>
    props.scrollDirection === 'up' &&
      !props.scrolledToTop &&
      css`
        height: 74px;
        transform: translateY(0px);
        background-color: rgba(255, 255, 255, 0.94);
        box-shadow: 0 10px 26px -22px rgba(31, 41, 55, 0.24);
      `};

    ${props =>
    props.scrollDirection === 'down' &&
      !props.scrolledToTop &&
      css`
        height: 74px;
        transform: translateY(-74px);
        box-shadow: 0 10px 26px -22px rgba(31, 41, 55, 0.24);
      `};
  }
`;

const StyledNav = styled.nav`
  ${({ theme }) => theme.mixins.flexBetween};
  position: relative;
  width: 100%;
  color: var(--lightest-slate);
  font-family: var(--font-ui);
  counter-reset: item 0;
  z-index: 12;

  .logo {
    ${({ theme }) => theme.mixins.flexCenter};

    a {
      color: var(--green);
      width: 42px;
      height: 42px;
      position: relative;
      z-index: 1;

      .hex-container {
        position: absolute;
        top: 0;
        left: 0;
        z-index: -1;
        @media (prefers-reduced-motion: no-preference) {
          transition: var(--transition);
        }
      }

      .logo-container {
        position: relative;
        z-index: 1;
        svg {
          fill: none;
          user-select: none;
          @media (prefers-reduced-motion: no-preference) {
            transition: var(--transition);
          }
          polygon {
            fill: var(--light-navy);
          }
        }
      }

      &:hover,
      &:focus {
        outline: 0;
        transform: translate(-4px, -4px);
        .hex-container {
          transform: translate(4px, 3px);
        }
      }
    }
  }
`;

const StyledLinks = styled.div`
  display: flex;
  align-items: center;
  gap: 16px;

  @media (max-width: 768px) {
    display: none;
  }

  ol {
    display: flex;
    align-items: center;
    gap: 6px;
    padding: 0;
    margin: 0;
    list-style: none;

    li {
      position: relative;
      counter-increment: item 1;
      font-size: var(--fz-md);

        a {
          padding: 12px 14px;
          border-radius: 10px;
          font-weight: 600;

        &.active {
          color: var(--green);
          font-weight: 700;
          background-color: rgba(255, 90, 79, 0.1);
        }

        &:before {
          content: '0' counter(item) '.';
          margin-right: 5px;
          color: var(--green);
          font-size: var(--fz-xxs);
          text-align: right;
        }
      }
    }
  }

  .resume-button {
    ${({ theme }) => theme.mixins.smallButton};
    font-size: var(--fz-sm);
  }
`;

const Nav = ({ isHome, isDarkEditorial, location }) => {
  const [isMounted] = useState(true);
  const scrollDirection = useScrollDirection('down');
  const [scrolledToTop, setScrolledToTop] = useState(true);
  const [activeNavLink, setActiveNavLink] = useState('');
  const prefersReducedMotion = usePrefersReducedMotion();
  const sectionNavLinks = useMemo(() => navLinks.filter(({ url }) => url.startsWith('/#')), []);

  const handleScroll = () => {
    setScrolledToTop(window.pageYOffset < 50);
  };

  useEffect(() => {
    window.addEventListener('scroll', handleScroll);

    return () => {
      window.removeEventListener('scroll', handleScroll);
    };
  }, []);

  useEffect(() => {
    if (isHome && location.hash) {
      setActiveNavLink(`/${location.hash}`);
      return;
    }

    if (!isHome) {
      if (location.pathname.startsWith('/blog')) {
        setActiveNavLink('/blog');
      } else {
        setActiveNavLink('');
      }
    }
  }, [isHome, location.hash, location.pathname]);

  useEffect(() => {
    if (!isHome || typeof window === 'undefined') {
      return undefined;
    }

    const sections = sectionNavLinks
      .map(({ url }) => ({
        id: url.replace('/#', ''),
        url,
        el: document.getElementById(url.replace('/#', '')),
      }))
      .filter(item => item.el);

    if (sections.length === 0) {
      return undefined;
    }

    const observer = new IntersectionObserver(
      entries => {
        const visibleEntries = entries
          .filter(entry => entry.isIntersecting)
          .sort((a, b) => b.intersectionRatio - a.intersectionRatio);

        if (visibleEntries.length > 0) {
          const activeEntry = visibleEntries[0];
          const activeSection = sections.find(item => item.el === activeEntry.target);
          if (activeSection) {
            setActiveNavLink(activeSection.url);
          }
        }
      },
      {
        rootMargin: '-35% 0px -55% 0px',
        threshold: [0.1, 0.25, 0.4, 0.6],
      },
    );

    sections.forEach(section => observer.observe(section.el));

    return () => {
      sections.forEach(section => observer.unobserve(section.el));
      observer.disconnect();
    };
  }, [isHome, sectionNavLinks]);

  const timeout = isHome ? loaderDelay : 0;
  const fadeClass = isHome ? 'fade' : '';
  const fadeDownClass = isHome ? 'fadedown' : '';

  const Logo = (
    <div className="logo" tabIndex="-1">
      {isHome ? (
        <a href="/" aria-label="home">
          <div className="hex-container">
            <IconHex />
          </div>
          <div className="logo-container">
            <IconLogo />
          </div>
        </a>
      ) : (
        <Link to="/" aria-label="home">
          <div className="hex-container">
            <IconHex />
          </div>
          <div className="logo-container">
            <IconLogo />
          </div>
        </Link>
      )}
    </div>
  );

  const ResumeLink = (
    <a className="resume-button" href="/resume.pdf" target="_blank" rel="noopener noreferrer">
      Resume
    </a>
  );

  return (
    <StyledHeader
      scrollDirection={scrollDirection}
      scrolledToTop={scrolledToTop}
      $darkEditorial={isDarkEditorial}>
      <StyledNav>
        {prefersReducedMotion ? (
          <>
            {Logo}

            <StyledLinks>
              <ol>
                {navLinks &&
                  navLinks.map(({ url, name }, i) => (
                    <li key={i}>
                      <Link
                        to={url}
                        className={activeNavLink === url ? 'active' : ''}
                        aria-current={activeNavLink === url ? 'page' : undefined}
                        onClick={() => setActiveNavLink(url)}>
                        {name}
                      </Link>
                    </li>
                  ))}
              </ol>
              <div>{ResumeLink}</div>
            </StyledLinks>

            <Menu activeNavLink={activeNavLink} onNavLinkClick={setActiveNavLink} />
          </>
        ) : (
          <>
            <TransitionGroup component={null}>
              {isMounted && (
                <CSSTransition classNames={fadeClass} timeout={timeout}>
                  <>{Logo}</>
                </CSSTransition>
              )}
            </TransitionGroup>

            <StyledLinks>
              <ol>
                <TransitionGroup component={null}>
                  {isMounted &&
                    navLinks &&
                    navLinks.map(({ url, name }, i) => (
                      <CSSTransition key={i} classNames={fadeDownClass} timeout={timeout}>
                        <li key={i} style={{ transitionDelay: `${isHome ? i * 100 : 0}ms` }}>
                          <Link
                            to={url}
                            className={activeNavLink === url ? 'active' : ''}
                            aria-current={activeNavLink === url ? 'page' : undefined}
                            onClick={() => setActiveNavLink(url)}>
                            {name}
                          </Link>
                        </li>
                      </CSSTransition>
                    ))}
                </TransitionGroup>
              </ol>

              <TransitionGroup component={null}>
                {isMounted && (
                  <CSSTransition classNames={fadeDownClass} timeout={timeout}>
                    <div style={{ transitionDelay: `${isHome ? navLinks.length * 100 : 0}ms` }}>
                      {ResumeLink}
                    </div>
                  </CSSTransition>
                )}
              </TransitionGroup>
            </StyledLinks>

            <TransitionGroup component={null}>
              {isMounted && (
                <CSSTransition classNames={fadeClass} timeout={timeout}>
                  <Menu activeNavLink={activeNavLink} onNavLinkClick={setActiveNavLink} />
                </CSSTransition>
              )}
            </TransitionGroup>
          </>
        )}
      </StyledNav>
    </StyledHeader>
  );
};

Nav.propTypes = {
  isHome: PropTypes.bool,
  isDarkEditorial: PropTypes.bool,
  location: PropTypes.shape({
    pathname: PropTypes.string,
    hash: PropTypes.string,
  }).isRequired,
};

export default Nav;
