import React, { useEffect, useRef } from 'react';
import { useStaticQuery, graphql } from 'gatsby';
import styled from 'styled-components';
import { srConfig } from '@config';
import sr from '@utils/sr';
import { usePrefersReducedMotion } from '@hooks';

const StyledJobsSection = styled.section`
  max-width: 100%;

  .jobs-list {
    display: grid;
    gap: 14px;
  }

  .resume-link {
    display: inline-flex;
    width: max-content;
    margin-top: 42px;
    color: var(--lightest-slate);
    font-family: var(--font-ui);
    font-size: var(--fz-lg);
    font-weight: 600;
    line-height: 1.2;
    text-decoration: none;
    transition: color 180ms ease;

    &:after {
      content: '↗';
      margin-left: 6px;
      color: var(--green);
      font-size: var(--fz-xs);
      transition: transform 180ms ease;
    }

    &:hover,
    &:focus-visible {
      color: var(--green);

      &:after {
        transform: translate(2px, -2px);
      }
    }
  }
`;

const StyledJob = styled.article`
  display: grid;
  grid-template-columns: minmax(150px, 190px) minmax(0, 1fr);
  gap: 32px;
  margin: 0 -22px;
  padding: 24px 22px;
  border: 1px solid transparent;
  border-radius: 14px;
  transition: background-color 180ms ease, border-color 180ms ease, box-shadow 180ms ease, transform 180ms ease;

  @media (max-width: 1200px) {
    grid-template-columns: minmax(136px, 168px) minmax(0, 1fr);
    gap: 24px;
  }

  @media (hover: hover) and (pointer: fine) {
    &:hover,
    &:focus-within {
      background-color: rgba(255, 255, 255, 0.72);
      border-color: rgba(82, 106, 120, 0.22);
      box-shadow: 0 18px 42px -30px var(--navy-shadow);
      transform: translateY(-2px);

      h3,
      .company a {
        color: var(--lightest-slate);
      }
    }
  }

  @media (max-width: 768px) {
    grid-template-columns: 1fr;
    gap: 10px;
    margin: 0;
    padding: 20px 0;
  }

  .range {
    color: var(--slate);
    font-family: var(--font-ui);
    font-size: var(--fz-md);
    font-weight: 600;
    letter-spacing: 0.04em;
    text-transform: uppercase;
    white-space: nowrap;
    padding-top: 4px;
  }

  .job-copy {
    min-width: 0;
  }

  .title-row {
    display: flex;
    flex-wrap: wrap;
    align-items: baseline;
    gap: 4px 8px;
    margin-bottom: 8px;
  }

  h3 {
    margin: 0;
    color: var(--lightest-slate);
    font-size: var(--fz-xl);
    font-weight: 600;
    line-height: 1.2;
    transition: color 180ms ease;
  }

  .company {
    color: var(--lightest-slate);

    a {
      color: inherit;
      transition: color 180ms ease;

      &:after {
        content: '↗';
        margin-left: 6px;
        color: var(--green);
        font-size: var(--fz-xs);
      }
    }
  }

  p {
    margin-bottom: 0;
    color: var(--slate);
    font-size: var(--fz-lg);
    line-height: 1.7;
    max-width: 58ch;
  }

  ul {
    display: none;
  }

  .tech-list {
    display: flex;
    flex-wrap: wrap;
    gap: 8px;
    margin: 16px 0 0;
    padding: 0;
    list-style: none;
  }

  .tech-chip {
    display: inline-flex;
    align-items: center;
    min-height: 32px;
    padding: 6px 14px;
    border: 1px solid rgba(82, 106, 120, 0.16);
    border-radius: 999px;
    color: #526a78;
    background-color: rgba(82, 106, 120, 0.1);
    font-family: var(--font-ui);
    font-size: var(--fz-sm);
    font-weight: 600;
    line-height: 1;
  }
`;

const Jobs = () => {
  const data = useStaticQuery(graphql`
    query {
      jobs: allMarkdownRemark(
        filter: { fileAbsolutePath: { regex: "/content/jobs/" } }
        sort: { fields: [frontmatter___date], order: DESC }
      ) {
        edges {
          node {
            frontmatter {
              title
              company
              range
              url
              tech
            }
            html
          }
        }
      }
    }
  `);

  const jobsData = data.jobs.edges;
  const revealContainer = useRef(null);
  const prefersReducedMotion = usePrefersReducedMotion();

  useEffect(() => {
    if (prefersReducedMotion) {
      return;
    }

    sr.reveal(revealContainer.current, srConfig());
  }, [prefersReducedMotion]);

  return (
    <StyledJobsSection id="jobs" ref={revealContainer}>
      <h2 className="numbered-heading">Where I’ve Worked</h2>

      <div className="jobs-list">
        {jobsData.map(({ node }, i) => {
          const { frontmatter, html } = node;
          const { title, url, company, range, tech } = frontmatter;

          return (
            <StyledJob key={`${company}-${i}`}>
              <div className="range">{range}</div>

              <div className="job-copy">
                <div className="title-row">
                  <h3>
                    <span>{title}</span>
                    <span className="company">
                      &nbsp;@&nbsp;
                      <a href={url}>{company}</a>
                    </span>
                  </h3>
                </div>

                <div dangerouslySetInnerHTML={{ __html: html }} />

                {tech && tech.length > 0 && (
                  <ul className="tech-list">
                    {tech.map(item => (
                      <li className="tech-chip" key={`${company}-${item}`}>
                        {item}
                      </li>
                    ))}
                  </ul>
                )}
              </div>
            </StyledJob>
          );
        })}
      </div>

      <a className="resume-link" href="/resume.pdf" target="_blank" rel="noopener noreferrer">
        View Full Résumé
      </a>
    </StyledJobsSection>
  );
};

export default Jobs;
